    public class VR4UIClickState : StructProxy
    {
        public VR4UIClickState(System.IntPtr ptr) : base(ptr) {}
        public EVR4UIAction Action { get => (EVR4UIAction)GetAt<byte>(0x0); set => SetAt(0x0, (byte)value); }
        public int ClickCount { get => GetAt<int>(0x4); set => SetAt(0x4, value); }
        public Vector PressWorldPosition => new Vector(AddrOf(0x8));
        public Vector ReleaseWorldPosition => new Vector(AddrOf(0x14));
        public float PressTime { get => GetAt<float>(0x20); set => SetAt(0x20, value); }
        public float ReleaseTime { get => GetAt<float>(0x24); set => SetAt(0x24, value); }
        public VR4PlayerHand Hand { get { var __p = GetAt<System.IntPtr>(0x28); return __p==System.IntPtr.Zero?null:new VR4PlayerHand(__p); } set => SetAt(0x28, value?.Pointer ?? System.IntPtr.Zero); }
    }

    public class VR4MenuEntryDescription : StructProxy
    {
        public VR4MenuEntryDescription(System.IntPtr ptr) : base(ptr) {}
        public System.IntPtr DisplayName => AddrOf(0x8); // 
        public string OwningMenuName => Native.FNameToString(GetAt<int>(0x20)); // FName
        public FName OwningMenuName_Raw { get => GetAt<FName>(0x20); set => SetAt(0x20, value); }
        public EVR4MenuWidgetType WidgetType { get => (EVR4MenuWidgetType)GetAt<byte>(0x28); set => SetAt(0x28, (byte)value); }
        public TArray<System.IntPtr> ToggleDisplayNames => new TArray<System.IntPtr>(AddrOf(0x30)); // TArray<FText>
        public string LinkMenuName => Native.FNameToString(GetAt<int>(0x40)); // FName
        public FName LinkMenuName_Raw { get => GetAt<FName>(0x40); set => SetAt(0x40, value); }
        public string PropertyName => Native.FNameToString(GetAt<int>(0x48)); // FName
        public FName PropertyName_Raw { get => GetAt<FName>(0x48); set => SetAt(0x48, value); }
        public float MinValue { get => GetAt<float>(0x50); set => SetAt(0x50, value); }
        public float MaxValue { get => GetAt<float>(0x54); set => SetAt(0x54, value); }
        public float SnapInterval { get => GetAt<float>(0x58); set => SetAt(0x58, value); }
        public string GetFuncName => Native.FNameToString(GetAt<int>(0x5C)); // FName
        public FName GetFuncName_Raw { get => GetAt<FName>(0x5C); set => SetAt(0x5C, value); }
        public string ApplyFuncName => Native.FNameToString(GetAt<int>(0x64)); // FName
        public FName ApplyFuncName_Raw { get => GetAt<FName>(0x64); set => SetAt(0x64, value); }
        public string ExecFuncName => Native.FNameToString(GetAt<int>(0x6C)); // FName
        public FName ExecFuncName_Raw { get => GetAt<FName>(0x6C); set => SetAt(0x6C, value); }
        public string DisplayFuncName => Native.FNameToString(GetAt<int>(0x74)); // FName
        public FName DisplayFuncName_Raw { get => GetAt<FName>(0x74); set => SetAt(0x74, value); }
        public System.IntPtr Description => AddrOf(0x80); // 
        public bool MercenariesModeOnly { get => (GetAt<byte>(0x98) & 0xFF) != 0; set { var __b = GetAt<byte>(0x98); SetAt(0x98, (byte)(value ? (__b | 0xFF) : (__b & ~0xFF))); } }
        public EVR4GameModeFilter GameModeFilter { get => (EVR4GameModeFilter)GetAt<byte>(0x99); set => SetAt(0x99, (byte)value); }
    }

    public class VR4Menu : StructProxy
    {
        public VR4Menu(System.IntPtr ptr) : base(ptr) {}
        public string Name => Native.FNameToString(GetAt<int>(0x0)); // FName
        public FName Name_Raw { get => GetAt<FName>(0x0); set => SetAt(0x0, value); }
        public VR4MenuEntryDescription Description => new VR4MenuEntryDescription(AddrOf(0x8));
